# [doc = " One-sided **unification** of a declared type (which may contain [`Ty::Var`] parameters) against a"] # [doc = " concrete `actual` type, accumulating the parameter substitution `s` (RFC-0007 §11.3). Used to"] # [doc = " **infer** a generic function's type arguments from its call-site argument types, and a constructor's"] # [doc = " from its field arguments. A parameter is bound at most once; a second, conflicting binding is an"] # [doc = " explicit mismatch (never a silent re-coercion — G2/VR-5). No `Swap` is ever inserted: a"] # [doc = " representation-level disagreement (`Binary{8}` vs `Binary{16}`) is an explicit error, not a"] # [doc = " conversion (S1)."] pub (crate) fn unify (site : & str , decl : & Ty , actual : & Ty , s : & mut BTreeMap < String , Ty > ,) -> Result < () , CheckError > { match (decl , actual) { (Ty :: Var (v) , _) => match s . get (v) { Some (bound) if bound != actual => Err (CheckError :: new (site , format ! ("type parameter `{v}` would have to be both {bound} and {actual} — \
                     an ambiguous instantiation, not a guess (RFC-0007 §11.3)") ,)) , _ => { s . insert (v . clone () , actual . clone ()) ; Ok (()) } } , (_ , Ty :: Var (_)) if decl == actual => Ok (()) , (Ty :: Data (n1 , a1) , Ty :: Data (n2 , a2)) if n1 == n2 && a1 . len () == a2 . len () => { for (d , a) in a1 . iter () . zip (a2) { unify (site , d , a , s) ? ; } Ok (()) } (Ty :: Fn (a1 , r1) , Ty :: Fn (a2 , r2)) => { unify (site , a1 , a2 , s) ? ; unify (site , r1 , r2 , s) } (Ty :: Seq (e1 , n1) , Ty :: Seq (e2 , n2)) if n1 == n2 => unify (site , e1 , e2 , s) , (Ty :: Binary (Width :: Var (v)) , Ty :: Binary (Width :: Lit (n))) | (Ty :: Ternary (Width :: Var (v)) , Ty :: Ternary (Width :: Lit (n))) => { let carrier = Ty :: Binary (Width :: Lit (* n)) ; match s . get (v) { Some (bound) if * bound != carrier => { let prior = match bound { Ty :: Binary (w) => w . to_string () , other => other . to_string () , } ; Err (CheckError :: new (site , format ! ("width parameter `{v}` would have to be both {prior} and {n} — a width mismatch, not a coercion (DN-42 §4 / VR-5)") ,)) } _ => { s . insert (v . clone () , carrier) ; Ok (()) } } } (Ty :: Binary (Width :: Var (v1)) , Ty :: Binary (Width :: Var (v2))) | (Ty :: Ternary (Width :: Var (v1)) , Ty :: Ternary (Width :: Var (v2))) => { let carrier = Ty :: Binary (Width :: Var (v2 . clone ())) ; match s . get (v1) { Some (bound) if * bound != carrier => Err (CheckError :: new (site , format ! ("width parameter `{v1}` would have to be both {bound} and the abstract width \
                         `{v2}` — an undetermined width, not a coercion (DN-42 §4 / VR-5)") ,)) , _ => { s . insert (v1 . clone () , carrier) ; Ok (()) } } } _ if decl == actual => Ok (()) , _ => Err (CheckError :: new (site , format ! ("cannot match {decl} against {actual} (RFC-0007 §11.3 — never a silent swap)") ,)) , } }

# [doc = " Resolve a surface [`TypeRef`] to a checked [`Ty`], with the type parameters `tyvars` in scope"] # [doc = " (RFC-0007 §11.2): a `Named(name, [])` whose `name` is a type parameter resolves to [`Ty::Var`];"] # [doc = " any other `Named` is a data type whose **arity is checked** against its declaration (`List<A>`"] # [doc = " applied to the wrong number of arguments is an explicit error, never a guess). VSA types resolve"] # [doc = " concretely as of M-892 (their surface model ident canonicalized to the kernel model id). The"] # [doc = " guarantee index is *allowed* and returned alongside (checked dynamically at"] # [doc = " stage 0 — RFC-0007 §4.3). `tyvars` is `&[]` in a monomorphic context."] pub (crate) fn resolve_ty (site : & str , types : & BTreeMap < String , DataInfo > , tyvars : & [String] , t : & TypeRef ,) -> Result < (Ty , Option < Strength >) , CheckError > { let base = match & t . base { BaseType :: Binary (WidthRef :: Lit (n)) => Ty :: Binary (Width :: Lit (* n)) , BaseType :: Binary (WidthRef :: Name (v)) => Ty :: Binary (Width :: Var (v . clone ())) , BaseType :: Ternary (WidthRef :: Lit (m)) => Ty :: Ternary (Width :: Lit (* m)) , BaseType :: Ternary (WidthRef :: Name (v)) => Ty :: Ternary (Width :: Var (v . clone ())) , BaseType :: Dense (d , s) => Ty :: Dense (* d , * s) , BaseType :: Substrate (tag) => Ty :: Substrate (tag . clone ()) , BaseType :: Seq { elem , len } => { let (elem_ty , _) = resolve_ty (site , types , tyvars , elem) ? ; Ty :: Seq (Box :: new (elem_ty) , * len) } BaseType :: Bytes => Ty :: Bytes , BaseType :: Float => Ty :: Float , BaseType :: Vsa { model , dim , sparsity , } => Ty :: Vsa { model : vsa_kernel_model_id (model) , dim : * dim , sparsity : sparsity . clone () , } , BaseType :: Named (name , args) => { if args . is_empty () && tyvars . iter () . any (| v | v == name) { Ty :: Var (name . clone ()) } else { let Some (decl) = types . get (name) else { return Err (CheckError :: new (site , format ! ("unknown type `{name}`"))) ; } ; if args . len () != decl . params . len () { return Err (CheckError :: new (site , format ! ("`{name}` takes {} type argument(s), got {} (RFC-0007 §11.3)" , decl . params . len () , args . len ()) ,)) ; } let mut resolved = Vec :: with_capacity (args . len ()) ; for a in args { resolved . push (resolve_ty (site , types , tyvars , a) ? . 0) ; } Ty :: Data (name . clone () , resolved) } } BaseType :: Ambient (_) => { return Err (CheckError :: new (site , "internal: an unresolved paradigm-less repr `{…}` reached the checker — the \
                 ambient resolution pass should have filled it (RFC-0012 §4.3)" ,)) ; } BaseType :: Fn (param , ret) => { let (param_ty , _) = resolve_ty (site , types , tyvars , param) ? ; let (ret_ty , _) = resolve_ty (site , types , tyvars , ret) ? ; Ty :: Fn (Box :: new (param_ty) , Box :: new (ret_ty)) } BaseType :: Tuple (elems) => { let n = elems . len () ; let tname = tuple_type_name (n) ; if ! types . contains_key (& tname) { return Err (CheckError :: new (site , format ! ("internal: synthetic tuple type `{tname}` not registered — \
                         `register_tuple_types` must run before the checker (M-826; never silent)") ,)) ; } let mut resolved = Vec :: with_capacity (n) ; for e in elems { resolved . push (resolve_ty (site , types , tyvars , e) ? . 0) ; } Ty :: Data (tname , resolved) } } ; Ok ((base , t . guarantee)) }

impl NoduleImports { # [doc = " The never-silent glob-vs-glob ambiguity refusal for `name`, if it is ambiguous here (G2)."] # [doc = " Returns `None` when the name is unambiguous (so the caller falls through to its own"] # [doc = " unknown-name diagnostic)."] fn ambiguity_error (& self , site : & str , name : & str) -> Option < CheckError > { self . ambiguous . contains (name) . then (| | { CheckError :: new (site , format ! ("`{name}` is ambiguous — imported by more than one glob `use … .*` in this \
                     nodule; import it explicitly (`use <path>.{name}`) to disambiguate (M-662; \
                     never a silent winner — G2)") ,) }) } }

# [doc = " **§4.1 IL-grammar RHS type-check** of a registered `lower` rule (DN-54 §4.1 / M-812-cont). The"] # [doc = " RHS must type-check as an L1 expression with the rule's type parameters in scope as abstract"] # [doc = " type-variables (the rule is parametric over the type it is derived for). An ill-typed / ill-formed"] # [doc = " RHS is an explicit refusal at definition time — so no `derive` site can invoke a rule that would"] # [doc = " produce broken L0. Run over the whole rule set *after* §4.2 acyclicity (so a cyclic set reports"] # [doc = " the cycle, not an \"unknown name\" for the cycle's rule-reference edge)."] # [doc = ""] # [doc = " **Guarantee: `Declared`** (a structural type/grammar check, not a theorem — VR-5) **layered with"] # [doc = " `Empirical`** (M-919; DN-71 Model S §4.2) for any `Substrate`-typed binding the RHS introduces —"] # [doc = " see the affine-tracker note below. The RHS has no *value parameters* in v0 (`lower Name[T] ="] # [doc = " <expr>`), so the value scope starts empty; the rule's `[…]` params are the *type* scope only. No"] # [doc = " expected type is pinned (a rule may lower to any well-typed term) — pure inference. The"] # [doc = " `@std-sys` gate is held **closed**: a `lower` rule is never an FFI escape (the §4.6 structural"] # [doc = " check already refused any direct `wild`; this is defense in depth)."] # [doc = ""] # [doc = " **Affine tracking is ACTIVE here, seeded empty (M-919 fix; DN-71 Model S §4.2).** A `lower`"] # [doc = " rule's RHS has no *initial* `Substrate` binding (no value params, no literal — DN-71 §4.1), but"] # [doc = " its RHS **can** legally introduce one mid-body: DN-54 §3.3 permits calling other already-checked"] # [doc = " top-level `fn`s, and nothing in v0 restricts those callees to non-affine return types, so a `let"] # [doc = " s = acquire_thing() in …` inside a rule's RHS can bind a real `Substrate{tag}` value (`acquire_thing`"] # [doc = " itself having gone through the ordinary `check_fn_body`'s active tracker at its own definition"] # [doc = " site, in an `@std-sys` nodule). An **inert** tracker here would silently exempt every such binding"] # [doc = " from the double-consume check ordinary function bodies get — a real, verified coverage gap (a"] # [doc = " probe reproduction confirmed a same-rule double-consume via a helper-fn-acquired `Substrate` type-checked"] # [doc = " under the pre-fix inert tracker). Seeding an **active-but-empty** tracker (mirroring"] # [doc = " `check_fn_body`'s `Tracker::seeded`, just from an empty initial scope, since a rule has no value"] # [doc = " params to seed from) closes this: every `let`/lambda/match binder pushed during the RHS walk is"] # [doc = " tracked exactly as it would be inside an ordinary function body, so a double-consume of a"] # [doc = " derive-site-acquired `Substrate` is refused here too, never silently."] fn check_lower_rule_rhs_type (ld : & LowerDecl , types : & BTreeMap < String , DataInfo > , fns : & BTreeMap < String , FnDecl > , traits : & BTreeMap < String , TraitInfo > , instances : & BTreeMap < (String , String) , InstanceInfo > , imports : & NoduleImports ,) -> Result < () , CheckError > { if let crate :: ast :: LowerRhs :: Impl (id) = & ld . rhs { let Some (tr) = traits . get (& id . trait_name) else { return Err (CheckError :: new (& ld . name , format ! ("`lower {}`'s item RHS is `impl {} for …`, but trait `{}` is not declared in \
                     scope (DN-54 §10.3 Model A; a derive template's trait must be visible — never \
                     silent, G2)" , ld . name , id . trait_name , id . trait_name) ,)) ; } ; check_impl_method_set (tr , id) . map_err (| e | { CheckError :: new (& ld . name , format ! ("`lower {}`'s item RHS `impl {} for …`: {}" , ld . name , id . trait_name , e . message) ,) }) ? ; return Ok (()) ; } let rhs = ld . expr_rhs () . expect ("item-shaped rules returned above; this is the expression arm") ; let cx = Cx { site : & ld . name , types , fns , traits , instances , imports , tyvars : & ld . params , bounds : & [] , std_sys : false , depth : Cell :: new (0) , affine : Tracker :: seeded (& []) , } ; let mut scope : Vec < (String , Ty) > = Vec :: new () ; cx . infer (& mut scope , rhs) . map_err (| e | { CheckError :: new (& ld . name , format ! ("`lower {}`'s RHS fails the IL-grammar / type check (DN-54 §4.1): {}" , ld . name , e . message) ,) }) ? ; Ok (()) }

# [doc = " Validate a `derive Name for T` use-site application (DN-54 §4 / M-812 / DN-38 §8.1)."] # [doc = ""] # [doc = " **Guarantee: `Declared`** (name-resolution + target-type + arity checks; the RHS instantiation"] # [doc = " + elaboration run at elaboration time, `Empirical` — VR-5)."] # [doc = ""] # [doc = " Checks (all never-silent, G2):"] # [doc = " - **Rule resolution**: `Name` must resolve to a registered `lower` rule in `lower_rules`"] # [doc = "   (earlier declarations in the same Pass 3e loop are already registered)."] # [doc = " - **Target type well-formedness**: `for_ty` must resolve to a real type (DN-54 §4)."] fn check_derive_application (dd : & DeriveDecl , lower_rules : & BTreeMap < String , LowerDecl > , types : & BTreeMap < String , DataInfo > ,) -> Result < () , CheckError > { if ! lower_rules . contains_key (& dd . name) { return Err (CheckError :: new (& dd . name , format ! ("`derive {}` references an unknown generative-lowering rule — declare it first \
                 with `lower {} […] = <rhs>` (DN-54 §4 / M-812; rule must be visible before use, \
                 G2). Did you spell the rule name correctly?" , dd . name , dd . name) ,)) ; } resolve_ty (& dd . name , types , & [] , & dd . for_ty) ? ; Ok (()) }

# [doc = " One body's effect coverage: `declared ⊇ performed`, where *performed* is the union of each"] # [doc = " callee's declared effects — a known top-level fn (`fns`), else an unqualified trait method"] # [doc = " (`traits`, by name) — **plus the `ffi` effect contributed by any `wild` block** (M-661). Owned-"] # [doc = " `String` sets keep lifetimes simple; the structural walk is shared with totality (one traversal,"] # [doc = " no bespoke depth-guarded recursion). Deterministic order ⇒ a stable first-miss diagnostic. The"] # [doc = " M-353 runtime budget ledger is a separate concern (not consulted here)."] fn check_body_effect_coverage (fns : & BTreeMap < String , FnDecl > , traits : & BTreeMap < String , TraitInfo > , name : & str , declared_effs : & [String] , body : & Expr ,) -> Result < () , CheckError > { let declared : std :: collections :: BTreeSet < String > = declared_effs . iter () . cloned () . collect () ; let mut performed : std :: collections :: BTreeSet < (String , EffectSource) > = std :: collections :: BTreeSet :: new () ; crate :: totality :: walk_expr (body , & mut | x | { match x { Expr :: App { head , .. } => { if let Expr :: Path (p) = head . as_ref () { if p . 0 . len () == 1 { let callee = & p . 0 [0] ; if let Some (g) = fns . get (callee) { for eff in & g . sig . effects { performed . insert ((eff . clone () , EffectSource :: Call (callee . clone ()))) ; } } else { for tr in traits . values () { for s in & tr . sigs { if & s . name == callee { for eff in & s . effects { performed . insert ((eff . clone () , EffectSource :: Call (callee . clone ()) ,)) ; } } } } } } } } Expr :: Wild (_) => { performed . insert (("ffi" . to_owned () , EffectSource :: Wild)) ; } _ => { } } }) . map_err (| e | CheckError :: new (name , e . to_string ())) ? ; for (eff , source) in & performed { if ! declared . contains (eff) { let via = match source { EffectSource :: Call (callee) => format ! ("via calling `{callee}`") , EffectSource :: Wild => "via a `wild` block (the FFI floor — M-661)" . to_owned () , } ; return Err (CheckError :: new (name , format ! ("`{name}` performs effect `{eff}` ({via}) but does not declare it — add it to \
                     the `!{{…}}` effect annotation (RFC-0014 §4.5 I3: no undeclared effects; never \
                     silent — G2)") ,)) ; } } Ok (()) }

# [doc = " **Trait pass** (RFC-0019 §4.2; LR-2 — guarantee: `Declared`, a structural registry check, not a"] # [doc = " theorem). Register each `trait Tr<params> { fn … }` as a [`TraitInfo`]: reject a duplicate trait"] # [doc = " name; reject duplicate type-parameter names and duplicate method names; and check that **every**"] # [doc = " method signature *resolves* with the trait's params in scope as abstract type-variables (its"] # [doc = " value-param types and return type via [`resolve_ty`]). A trait is a registry entry, never a"] # [doc = " kernel node (KC-3). Every refusal is an explicit [`CheckError`] (G2)."] pub (crate) fn register_traits (types : & BTreeMap < String , DataInfo > , nodule : & Nodule ,) -> Result < BTreeMap < String , TraitInfo > , CheckError > { let mut traits : BTreeMap < String , TraitInfo > = BTreeMap :: new () ; for item in & nodule . items { let Item :: Trait (td) = item else { continue } ; let site = & td . name ; if let Some (dup) = first_duplicate (& td . params) { return Err (CheckError :: new (site , format ! ("duplicate type parameter `{dup}` in trait `{}`" , td . name) ,)) ; } if traits . contains_key (& td . name) { return Err (CheckError :: new (site , "duplicate trait declaration")) ; } let mut seen_methods : std :: collections :: BTreeSet < & str > = std :: collections :: BTreeSet :: new () ; for s in & td . sigs { if ! seen_methods . insert (s . name . as_str ()) { return Err (CheckError :: new (site , format ! ("duplicate method `{}` in trait `{}`" , s . name , td . name) ,)) ; } let mut tyvars = td . params . clone () ; tyvars . extend (s . param_names ()) ; check_sig_resolves (types , site , & tyvars , s) ? ; } traits . insert (td . name . clone () , TraitInfo { name : td . name . clone () , params : td . params . clone () , sigs : td . sigs . clone () , } ,) ; } for tr in traits . values () { for s in & tr . sigs { for tp in & s . params { for b in & tp . bounds { if ! traits . contains_key (& b . name) { return Err (CheckError :: new (& tr . name , format ! ("trait `{}` method `{}`: unknown trait `{}` in the bound `{}: {}` \
                                 (RFC-0019 §4.1 — a method's type-parameter bound must name a \
                                 declared trait)" , tr . name , s . name , b . name , tp . name , b . name) ,)) ; } } } } } Ok (traits) }

# [doc = " Check one `impl`'s method bodies against their **expected** signatures (RFC-0019 §4.5; guarantee:"] # [doc = " `Declared` — a structural check). The expected signature of method `m` is the trait's sig for `m`"] # [doc = " with the trait's params substituted by this impl's `trait_args`; the method body is checked the"] # [doc = " normal fn-body way against those substituted value-param/return types. A signature mismatch"] # [doc = " (wrong param types or arity, wrong return) is an explicit refusal, never silently accepted."] fn check_impl_methods (types : & BTreeMap < String , DataInfo > , fns : & BTreeMap < String , FnDecl > , traits : & BTreeMap < String , TraitInfo > , instances : & BTreeMap < (String , String) , InstanceInfo > , imports : & NoduleImports , std_sys : bool , id : & ImplDecl ,) -> Result < Vec < FnDecl > , CheckError > { let tr = traits . get (& id . trait_name) . expect ("instance registration checked the trait exists") ; let mut resolved : Vec < FnDecl > = Vec :: with_capacity (id . methods . len ()) ; let (for_ty , _) = resolve_ty (& id . trait_name , types , & [] , & id . for_ty) ? ; let mut trait_args = Vec :: with_capacity (id . trait_args . len ()) ; for a in & id . trait_args { trait_args . push (resolve_ty (& id . trait_name , types , & [] , a) ? . 0) ; } let s = param_subst (& tr . params , & trait_args) ; for method in & id . methods { let req = tr . sigs . iter () . find (| x | x . name == method . sig . name) . expect ("method-set match checked at registration") ; let site = & method . sig . name ; if method . sig . value_params . len () != req . value_params . len () { return Err (CheckError :: new (site , format ! ("impl method `{}` of `{}` takes {} parameter(s), but the trait requires {}" , method . sig . name , tr . name , method . sig . value_params . len () , req . value_params . len ()) ,)) ; } for (mp , rp) in method . sig . value_params . iter () . zip (& req . value_params) { let (got , _) = resolve_ty (site , types , & [] , & mp . ty) ? ; let want = subst_ty (& resolve_ty (site , types , & tr . params , & rp . ty) ? . 0 , & s) ; if got != want { return Err (CheckError :: new (site , format ! ("impl method `{}` parameter `{}`: {}" , method . sig . name , mp . name , edge_mismatch ("type" , & want , & got)) ,)) ; } } let (got_ret , _) = resolve_ty (site , types , & [] , & method . sig . ret) ? ; let want_ret = subst_ty (& resolve_ty (site , types , & tr . params , & req . ret) ? . 0 , & s) ; if got_ret != want_ret { return Err (CheckError :: new (site , format ! ("impl method `{}` return: {}" , method . sig . name , edge_mismatch ("type" , & want_ret , & got_ret)) ,)) ; } let req_effects : std :: collections :: BTreeSet < & str > = req . effects . iter () . map (String :: as_str) . collect () ; let got_effects : std :: collections :: BTreeSet < & str > = method . sig . effects . iter () . map (String :: as_str) . collect () ; if req_effects != got_effects { return Err (CheckError :: new (site , format ! ("impl method `{}` declares effects {} but trait `{}` requires {} — an impl \
                     method's effect annotation must match the trait method's exactly (RFC-0014 \
                     §4.5 I3; never silently widened or narrowed — G2)" , method . sig . name , render_effects (& method . sig . effects) , tr . name , render_effects (& req . effects) ,) ,)) ; } let (body , _ret) = check_fn_body (types , fns , traits , instances , imports , std_sys , method) ? ; resolved . push (FnDecl { vis : method . vis , thaw : method . thaw , tier : method . tier , sig : method . sig . clone () , body , }) ; } let _ = for_ty ; Ok (resolved) }
